   102→// src/controllers/user.controller.ts
   103→import { Request, Response, NextFunction } from 'express';
   104→import { UserService } from '../services/user.service';
   105→import * as Sentry from '@sentry/node';
   106→
   107→export class UserController {
   108→  private userService: UserService;
