   273→## Error Handling
   274→
   275→### Global Error Middleware
   276→
   277→```typescript
   278→// src/middleware/error.middleware.ts
   279→import { Request, Response, NextFunction } from 'express';
   280→import * as Sentry from '@sentry/node';
   281→
   282→export class AppError extends Error {
   283→  statusCode: number;
   284→  isOperational: boolean;
   285→
   286→  constructor(message: string, statusCode: number = 500) {
   287→    super(message);
   288→    this.statusCode = statusCode;
   289→    this.isOperational = true;
   290→
   291→    Error.captureStackTrace(this, this.constructor);
   292→  }
   293→}
   294→
   295→export const errorHandler = (
   296→  error: Error | AppError,
   297→  req: Request,
   298→  res: Response,
   299→  next: NextFunction
   300→): void => {
   301→  let statusCode = 500;
   302→  let message = 'Internal server error';
   303→
   304→  if (error instanceof AppError) {
   305→    statusCode = error.statusCode;
   306→    message = error.message;
   307→  }
   308→
   309→  // Log to Sentry (all errors)
   310→  Sentry.captureException(error, {
   311→    tags: {
   312→      path: req.path,
   313→      method: req.method
   314→    },
   315→    extra: {
   316→      body: req.body,
   317→      query: req.query,
   318→      params: req.params
   319→    }
   320→  });
   321→
   322→  // Don't leak error details in production
   323→  const isDevelopment = process.env.NODE_ENV === 'development';
   324→
   325→  res.status(statusCode).json({
   326→    success: false,
   327→    error: message,
   328→    ...(isDevelopment && { stack: error.stack })
   329→  });
   330→};
   331→
   332→// Usage in app.ts
   333→app.use(errorHandler);
   334→```
